pub fn lua_len(state: &mut LuaState, idx: i32) -> Result<i64, LuaError> {
    // C: lua_len(L, idx);
    state.len_op(idx)?;
    // C: l = lua_tointegerx(L, -1, &isnum);
    let l = match state.to_integer_x(-1) {
        Some(n) => n,
        None => {
            return Err(LuaError::runtime(format_args!(
                "object length is not an integer"
            )));
        }
    };
    // C: lua_pop(L, 1);
    state.pop_n(1);
    Ok(l)
}

