/// C: static void mainfunc(LexState *ls, FuncState *fs)
/// Compiles the main chunk (always a vararg function with _ENV upvalue).
fn mainfunc(ls: &mut LexState, state: &mut LuaState, main_fs: FuncState) -> Result<(), LuaError> {
