    // C: setvararg(fs, 0) — main function is always vararg
    setvararg(ls.fs.as_mut().unwrap(), state, 0)?;

    // C: env = allocupvalue(fs); env->instack=1; env->idx=0; env->kind=VDKREG; env->name=ls->envn
    let env_name = ls.envn.clone();
